import { WorkflowIndex } from "../features/workflow/types/workflow";

interface ProjectEntry {
  key: string;
  path: string;
  defaultEnv: string;
}

export function generateBashOrchestrator(
  projects: ProjectEntry[]
): string {
  const sorted = [...projects].sort((a, b) => b.path.length - a.path.length);

  const projectMatchLines = sorted.map(
    (p) =>
      `  "${p.path}")\n    PROJECT_KEY="${p.key}"\n    DEFAULT_ENV="${p.defaultEnv}"\n    ;;`
  ).join("\n");

  return [
    "#! /usr/bin/env bash",
    "# Generated by Project Igniter",
    "",
    'set -o pipefail',
    "",
    '# ── Locate .project-igniter root ──',
    'PROJECT_IGNITER_DIR=""',
    'CURRENT_DIR="$PWD"',
    'while [ "$CURRENT_DIR" != "/" ]; do',
    '  if [ -d "$CURRENT_DIR/.project-igniter" ]; then',
    '    PROJECT_IGNITER_DIR="$CURRENT_DIR/.project-igniter"',
    '    break',
    '  fi',
    '  CURRENT_DIR="$(dirname "$CURRENT_DIR")"',
    'done',
    'if [ -z "$PROJECT_IGNITER_DIR" ]; then',
    '  echo "Error: .project-igniter not found in any parent directory" >&2',
    '  exit 1',
    'fi',
    'WORKFLOWS_JSON="$PROJECT_IGNITER_DIR/workflows.json"',
    'PROJECT_ROOT="$(cd "$PROJECT_IGNITER_DIR/.." && pwd)"',
    "",
    '# ── Determine project key from cwd ──',
    'CWD_REL="${PWD#$PROJECT_ROOT}"',
    'CWD_REL="${CWD_REL#/}"',
    'CWD_REL="${CWD_REL:-.}"',
    'PROJECT_KEY=""',
    'DEFAULT_ENV="dev"',
    "",
    'case "$CWD_REL" in',
    projectMatchLines,
    '  *)',
    '    echo "Error: current directory does not match any project in workflows.json" >&2',
    '    exit 1',
    '    ;;',
    'esac',
    "",
    '# ── Parse flags ──',
    'ENV="$DEFAULT_ENV"',
    'SYNC=false',
    'RESET=false',
    'STATUS=false',
    '',
    'while [ $# -gt 0 ]; do',
    '  case "$1" in',
    '    --env) ENV="$2"; shift 2 ;;',
    '    --sync) SYNC=true; shift ;;',
    '    --reset) RESET=true; shift ;;',
    '    --status) STATUS=true; shift ;;',
    '    --help)',
    '      echo "Usage: setup.sh [--env <name>] [--sync] [--reset] [--status]"',
    '      echo ""',
    '      echo "  --env <name>   Target environment (default: $DEFAULT_ENV)"',
    '      echo "  --sync         Refresh inputs without clearing existing ones"',
    '      echo "  --reset        Clear all stored state for this project/env"',
    '      echo "  --status       Show current configuration status"',
    '      exit 0',
    '      ;;',
    '    *) echo "Unknown flag: $1" >&2; exit 1 ;;',
    '  esac',
    'done',
    "",
    '# ── State management ──',
    'STATE_BASE="${HOME}/.local/share/project-igniter"',
    'SAFE_PROJECT="$(echo "$PROJECT_KEY" | sed "s/[^a-zA-Z0-9]/_/g")"',
    'SAFE_ENV="$(echo "$ENV" | sed "s/[^a-zA-Z0-9]/_/g")"',
    'STATE_DIR="${STATE_BASE}/${SAFE_PROJECT}/${SAFE_ENV}"',
    'STATE_META="${STATE_DIR}/meta"',
    'mkdir -p "$STATE_DIR" 2>/dev/null',
    "",
    '# ── Drift detection ──',
    'CURRENT_SCHEMA="$(grep -o \'"schema":[0-9]*\' "$WORKFLOWS_JSON" | grep -o \'[0-9]*$\' | head -1)"',
    'STORED_SCHEMA="$(test -f "$STATE_META" && grep "SCHEMA=" "$STATE_META" | cut -d= -f2 || echo "")"',
    '',
    'if [ -n "$STORED_SCHEMA" ] && [ "$STORED_SCHEMA" != "$CURRENT_SCHEMA" ]; then',
    '  echo "Warning: workflow schema changed ($STORED_SCHEMA → $CURRENT_SCHEMA)." >&2',
    '  echo "Run ./setup.sh --sync to update state." >&2',
    '  exit 1',
    'fi',
    "",
    '# ── Commands ──',
    'if [ "$RESET" = true ]; then',
    '  rm -rf "$STATE_DIR"',
    '  echo "State cleared for project=${PROJECT_KEY} env=${ENV}"',
    '  exit 0',
    'fi',
    '',
    'if [ "$STATUS" = true ]; then',
    '  echo "Project: ${PROJECT_KEY}"',
    '  echo "Environment: ${ENV}"',
    '  echo "Schema: ${CURRENT_SCHEMA}"',
    '  if [ -f "$STATE_META" ]; then',
    '    echo "Last run: $(grep "LAST_RUN=" "$STATE_META" | cut -d= -f2)"',
    '  fi',
    '  echo ""',
    '  if [ -d "$STATE_DIR" ]; then',
    '    for f in "$STATE_DIR"/*; do',
    '      [ "$(basename "$f")" = "meta" ] && continue',
    '      echo "  $(basename "$f") = $(cat "$f")"',
    '    done',
    '  fi',
    '  exit 0',
    'fi',
    "",
    '# ── Update state meta ──',
    'echo "SCHEMA=${CURRENT_SCHEMA}" > "$STATE_META"',
    'echo "LAST_RUN=$(date +%Y-%m-%d)" >> "$STATE_META"',
    "",
    '# ── Run target script ──',
    'TARGET_SCRIPT="$PROJECT_IGNITER_DIR/scripts/${PROJECT_KEY}/${ENV}/setup.sh"',
    'if [ ! -f "$TARGET_SCRIPT" ]; then',
    '  echo "Error: no setup script found for project=${PROJECT_KEY} env=${ENV}" >&2',
    '  echo "  Expected: $TARGET_SCRIPT" >&2',
    '  exit 1',
    'fi',
    '',
    'export SYNC_MODE="$SYNC"',
    'exec "$TARGET_SCRIPT"',
    "",
  ].join("\n");
}

export function generatePowerShellOrchestrator(
  projects: ProjectEntry[]
): string {
  const sorted = [...projects].sort((a, b) => b.path.length - a.path.length);

  const projectMatchLines = sorted.map(
    (p) =>
      `    "${p.path}") {\n      $PROJECT_KEY = '${p.key}'\n      $DEFAULT_ENV = '${p.defaultEnv}'\n    }`
  ).join("\n");

  return [
    "# Generated by Project Igniter",
    "",
    '$ErrorActionPreference = "Stop"',
    "",
    '# ── Locate .project-igniter root ──',
    '$PROJECT_IGNITER_DIR = $null',
    '$CURRENT_DIR = Get-Location',
    'while ($CURRENT_DIR -ne $null -and $CURRENT_DIR -ne [System.IO.Path]::GetPathRoot($CURRENT_DIR)) {',
    '  $testPath = Join-Path $CURRENT_DIR ".project-igniter"',
    '  if (Test-Path $testPath) {',
    '    $PROJECT_IGNITER_DIR = $testPath',
    '    break',
    '  }',
    '  $CURRENT_DIR = Split-Path $CURRENT_DIR -Parent',
    '}',
    'if ($null -eq $PROJECT_IGNITER_DIR) {',
    '  Write-Error ".project-igniter not found in any parent directory"',
    '  exit 1',
    '}',
    '$WORKFLOWS_JSON = Join-Path $PROJECT_IGNITER_DIR "workflows.json"',
    '$PROJECT_ROOT = Split-Path $PROJECT_IGNITER_DIR -Parent',
    "",
    '# ── Determine project key from cwd ──',
    '$CWD_REL = (Get-Location).FullName.Substring($PROJECT_ROOT.Length).TrimStart("/\\")',
    'if ([string]::IsNullOrEmpty($CWD_REL)) { $CWD_REL = "." }',
    '$PROJECT_KEY = ""',
    '$DEFAULT_ENV = "dev"',
    "",
    'switch -Wildcard ($CWD_REL) {',
    projectMatchLines,
    '  default {',
    '    Write-Error "current directory does not match any project in workflows.json"',
    '    exit 1',
    '  }',
    '}',
    "",
    '# ── Parse flags ──',
    '$ENV = $DEFAULT_ENV',
    '$SYNC = $false',
    '$RESET = $false',
    '$STATUS = $false',
    '',
    'while ($args.Count -gt 0) {',
    '  switch ($args[0]) {',
    '    "--env") { $ENV = $args[1]; $args = $args[2..$args.Count] }',
    '    "--sync") { $SYNC = $true; $args = $args[1..$args.Count] }',
    '    "--reset") { $RESET = $true; $args = $args[1..$args.Count] }',
    '    "--status") { $STATUS = $true; $args = $args[1..$args.Count] }',
    '    "--help") {',
    '      Write-Host "Usage: setup.ps1 [--env <name>] [--sync] [--reset] [--status]"',
    '      Write-Host ""',
    '      Write-Host "  --env <name>   Target environment (default: $DEFAULT_ENV)"',
    '      Write-Host "  --sync         Refresh inputs without clearing existing ones"',
    '      Write-Host "  --reset        Clear all stored state for this project/env"',
    '      Write-Host "  --status       Show current configuration status"',
    '      exit 0',
    '    }',
    '    default { Write-Error "Unknown flag: $($args[0])"; exit 1 }',
    '  }',
    '}',
    "",
    '# ── State management ──',
    '$STATE_BASE = "$env:HOME/.local/share/project-igniter"',
    '$SAFE_PROJECT = [regex]::Replace($PROJECT_KEY, "[^a-zA-Z0-9]", "_")',
    '$SAFE_ENV = [regex]::Replace($ENV, "[^a-zA-Z0-9]", "_")',
    '$STATE_DIR = Join-Path $STATE_BASE "$SAFE_PROJECT/$SAFE_ENV"',
    '$STATE_META = Join-Path $STATE_DIR "meta"',
    'New-Item -ItemType Directory -Path $STATE_DIR -Force | Out-Null',
    "",
    '# ── Drift detection ──',
    '$CURRENT_SCHEMA = (Select-String -Path $WORKFLOWS_JSON -Pattern \x27schema":(\d+)\x27 | ForEach-Object { $_.Matches.Groups[1].Value } | Select-Object -First 1)',
    '$STORED_SCHEMA = if (Test-Path $STATE_META) { (Get-Content $STATE_META | Select-String "SCHEMA=(.*)" | ForEach-Object { $_.Matches.Groups[1].Value }) } else { $null }',
    '',
    'if ($STORED_SCHEMA -and $STORED_SCHEMA -ne $CURRENT_SCHEMA) {',
    '  Write-Warning "Workflow schema changed ($STORED_SCHEMA → $CURRENT_SCHEMA)."',
    '  Write-Warning "Run ./setup.ps1 --sync to update state."',
    '  exit 1',
    '}',
    "",
    '# ── Commands ──',
    'if ($RESET) {',
    '  Remove-Item -Path $STATE_DIR -Recurse -Force -ErrorAction SilentlyContinue',
    '  Write-Host "State cleared for project=$PROJECT_KEY env=$ENV"',
    '  exit 0',
    '}',
    '',
    'if ($STATUS) {',
    '  Write-Host "Project: $PROJECT_KEY"',
    '  Write-Host "Environment: $ENV"',
    '  Write-Host "Schema: $CURRENT_SCHEMA"',
    '  if (Test-Path $STATE_META) {',
    '    $lastRun = (Get-Content $STATE_META | Select-String "LAST_RUN=(.*)").Matches.Groups[1].Value',
    '    Write-Host "Last run: $lastRun"',
    '  }',
    '  Write-Host ""',
    '  if (Test-Path $STATE_DIR) {',
    '    Get-ChildItem $STATE_DIR | Where-Object { $_.Name -ne "meta" } | ForEach-Object {',
    '      Write-Host "  $($_.Name) = $(Get-Content $_.FullName)"',
    '    }',
    '  }',
    '  exit 0',
    '}',
    "",
    '# ── Update state meta ──',
    '"SCHEMA=$CURRENT_SCHEMA" | Out-File $STATE_META -Encoding UTF8',
    '"LAST_RUN=$(Get-Date -Format yyyy-MM-dd)" | Out-File $STATE_META -Append -Encoding UTF8',
    "",
    '# ── Run target script ──',
    '$TARGET_SCRIPT = Join-Path $PROJECT_IGNITER_DIR "scripts" $PROJECT_KEY $ENV "setup.ps1"',
    'if (-not (Test-Path $TARGET_SCRIPT)) {',
    '  Write-Error "No setup script found for project=$PROJECT_KEY env=$ENV"',
    '  Write-Error "  Expected: $TARGET_SCRIPT"',
    '  exit 1',
    '}',
    '',
    '$env:SYNC_MODE = if ($SYNC) { "true" } else { "false" }',
    '& $TARGET_SCRIPT',
    "",
  ].join("\n");
}

export function extractProjects(index: WorkflowIndex): ProjectEntry[] {
  return Object.entries(index.projects).map(([key, proj]) => ({
    key,
    path: proj.path,
    defaultEnv: proj.defaultEnv,
  }));
}
